import*as Browser from"@hyperjump/browser";import*as Instance from"../instance.js";import{getKeywordName,Validation}from"../experimental.js";const id="https://json-schema.org/keyword/contains",compile=async(e,t,r)=>{var t=await Validation.compile(e,t),n=getKeywordName(e.document.dialectId,"https://json-schema.org/keyword/minContains"),n=await Browser.step(n,r),n="number"===Browser.typeOf(n)?Browser.value(n):1,e=getKeywordName(e.document.dialectId,"https://json-schema.org/keyword/maxContains"),e=await Browser.step(e,r);return{contains:t,minContains:n,maxContains:"number"===Browser.typeOf(e)?Browser.value(e):Number.MAX_SAFE_INTEGER}},interpret=({contains:e,minContains:t,maxContains:r},n,a)=>{if("array"!==Instance.typeOf(n))return!0;let o=0,i=0;for(const s of Instance.iter(n))Validation.interpret(e,s,a)&&(o++,a.evaluatedItems?.add(i)),i++;return o>=t&&o<=r};export default{id:id,compile:compile,interpret:interpret};